input.content:
//! `--config none|<path>` flag — controls whether a subcommand
//! writes its canned `.vc-config.toml` or substitutes a
//! user-provided file.
//!
//! - `ConfigKind::None` — skip writing entirely.
//! - `ConfigKind::Path(p)` — copy `p` into place instead of the
//!   canned content.
//! - Absence of the flag (`Option<ConfigKind>::None` at the arg
//!   layer) is the canonical default — caller writes its canned
//!   content. No `Default` variant on this enum; clap's `Option`
//!   handles "no value", matching `args::ScopeKind`'s shape.

use std::path::PathBuf;

/// Parsed `--config` value.
///
/// - `None` — explicit skip (`--config none`).
/// - `Path(p)` — explicit user-provided file (`--config <path>`).
#[derive(Clone, Debug, PartialEq, Eq)]
pub enum ConfigKind {
    None,
    Path(PathBuf),
}

/// Parse the `--config` value into a `ConfigKind`.
///
/// - `none` (literal keyword) → `ConfigKind::None`.
/// - Anything else (non-empty) → `ConfigKind::Path(s.into())`.
/// - Empty input errors.
///
/// No path-prefix discipline (`./`, `~/`, etc.) — `--config` has
/// only one keyword (`none`), so any other string is unambiguously
/// a path. Path validation (existence, readability) happens at the
/// consumer's preflight, not here.
pub fn parse_config_kind(s: &str) -> Result<ConfigKind, String> {
    if s.is_empty() {
        return Err("--config: value is empty (use 'none' or a path)".into());
    }
    if s == "none" {
        return Ok(ConfigKind::None);
    }
    Ok(ConfigKind::Path(PathBuf::from(s)))
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn keyword_none() {
        assert_eq!(parse_config_kind("none").unwrap(), ConfigKind::None);
    }

    #[test]
    fn relative_path() {
        assert_eq!(
            parse_config_kind("./my-config.toml").unwrap(),
            ConfigKind::Path(PathBuf::from("./my-config.toml")),
        );
    }

    #[test]
    fn absolute_path() {
        assert_eq!(
            parse_config_kind("/etc/vc-x1/config.toml").unwrap(),
            ConfigKind::Path(PathBuf::from("/etc/vc-x1/config.toml")),
        );
    }

    #[test]
    fn home_relative_path() {
        assert_eq!(
            parse_config_kind("~/configs/foo.toml").unwrap(),
            ConfigKind::Path(PathBuf::from("~/configs/foo.toml")),
        );
    }

    #[test]
    fn bare_filename_treated_as_path() {
        // No `./` prefix discipline — single keyword `none`, anything
        // else is a path. Existence-check happens at consumer preflight.
        assert_eq!(
            parse_config_kind("foo.toml").unwrap(),
            ConfigKind::Path(PathBuf::from("foo.toml")),
        );
    }

    #[test]
    fn empty_errors() {
        let err = parse_config_kind("").unwrap_err();
        assert!(err.contains("empty"), "unexpected message: {err}");
    }
}

